mapper.select:
SELECT id, comment_id, comment_user_id, user_id, like_status,
       liked_at, canceled_at, created_at, updated_at
FROM bluenote_comment.comment_like
WHERE comment_id = #{commentId}
  AND user_id = #{userId}

mapper.update:
UPDATE bluenote_comment.comment_like
SET like_status = 'CANCELED',
    canceled_at = #{canceledAt},
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND like_status = 'ACTIVE'
